const norm=t=>t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/['']/g," ").replace(/[-–—]/g," ").replace(/[^a-z0-9\s]/g,"").replace(/\s+/g," ").trim();
const tok=t=>norm(t).split(" ").filter(w=>w.length>1&&!SW.has(w));
const bi=ts=>{const b=[];for(let i=0;i<ts.length-1;i++)b.push(ts[i]+" "+ts[i+1]);return b};
function detectIntent(t){const l=t.toLowerCase(),r=[];if(/pourquoi|raison|cause|expliqu/.test(l))r.push({type:"expliquer",label:"Expliquer / Justifier",icon:"💡"});if(/comment|de quelle mani|par quel|proc/.test(l))r.push({type:"mecanisme",label:"Décrire un mécanisme",icon:"⚙️"});if(/compar|diff[eé]ren|oppos|versus|vs/.test(l))r.push({type:"comparer",label:"Comparer",icon:"⚖️"});if(/exemple|illustr|cas|concr/.test(l))r.push({type:"illustrer",label:"Illustrer",icon:"📌"});if(/quel|impact|cons[eé]quence|effet|influence|r[oô]le/.test(l))r.push({type:"analyser",label:"Analyser",icon:"🔍"});if(/peut-on|faut-il|doit-on|est-il|est-ce/.test(l))r.push({type:"debattre",label:"Débattre",icon:"💬"});if(!r.length)r.push({type:"general",label:"Explorer",icon:"🧭"});return r}
function sc(f,qt,qb){let s=0;const mc=f.motsCles,ad=mc.directs.map(norm),ai=mc.indirects.map(norm),as=mc.synonymes.map(norm),ap=mc.notionsProches.map(norm),nt=norm(f.titre),nd=norm(f.definition);for(const t of qt){if(ad.some(k=>k.includes(t)||t.includes(k)))s+=3;if(ai.some(k=>k.includes(t)||t.includes(k)))s+=2;if(as.some(k=>k.includes(t)||t.includes(k)))s+=1.5;if(ap.some(k=>k.includes(t)||t.includes(k)))s+=1;if(nt.includes(t))s+=2;if(nd.includes(t))s+=.5}for(const b of qb){if(ad.some(k=>k.includes(b)||b.includes(k)))s+=4;if(ai.some(k=>k.includes(b)||b.includes(k)))s+=2.5}return s}
function search(q){const ts=tok(q),bs=bi(ts),intents=detectIntent(q);let r=F.map(f=>({...f,score:sc(f,ts,bs)})).filter(f=>f.score>0).sort((a,b)=>b.score-a.score);const mx=r[0]?.score||1;r=r.map(x=>({...x,rel:Math.min(100,Math.round(x.score/mx*100))}));const p=r.slice(0,5),pids=new Set(p.map(x=>x.id)),rids=new Set();p.forEach(x=>(x.liensAutresConcepts||[]).forEach(id=>{if(!pids.has(id))rids.add(id)}));const sec=F.filter(f=>rids.has(f.id)&&!pids.has(f.id)).slice(0,4);const pi=[];p.forEach(x=>(x.pistesDargumentation||[]).forEach(a=>{if(!pi.includes(a))pi.push(a)}));return{principaux:p,secondaires:sec,intents,pistes:pi.slice(0,6),total:r.length}}

/* ═══════════════════════════════════════════════════════════════
   🎨 LINKED-U DESIGN SYSTEM
   ═══════════════════════════════════════════════════════════════ */
const TC={
  theme1:{label:"Définition de l'offre",color:"#6C5CE7",bg:"#EDE9FF",grad:"linear-gradient(135deg,#6C5CE7,#A29BFE)",icon:"📦"},
  theme2:{label:"Distribution de l'offre",color:"#00B894",bg:"#E0FFF5",grad:"linear-gradient(135deg,#00D2A0,#74B9FF)",icon:"🚚"},
  theme3:{label:"Communication de l'offre",color:"#E17055",bg:"#FFE8E8",grad:"linear-gradient(135deg,#FD79A8,#FDCB6E)",icon:"📢"},
};
const EX=["Comment une marque peut-elle créer de la confiance ?","Pourquoi les entreprises personnalisent-elles leur offre ?","Quel est le rôle du packaging dans l'acte d'achat ?","Comment le numérique transforme-t-il la distribution ?","La gratuité est-elle un bon modèle économique ?","Comment fidéliser ses clients grâce aux réseaux sociaux ?","Le yield management est-il juste pour le consommateur ?","Pourquoi les avis en ligne influencent-ils nos achats ?"];

/* ═══════════════════════════════════════════════════════════════
   🧩 COMPONENTS
   ═══════════════════════════════════════════════════════════════ */
const G=`@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&display=swap');*{margin:0;padding:0;box-sizing:border-box}:root{--bg:#FFFBF5;--sf:#fff;--bd:#F0E8DD;--ink:#1A1A2E;--ink2:#4A4A6A;--ink3:#8888A8;--el:#6C5CE7;--co:#FF6B6B;--li:#00D2A0;--su:#FDCB6E;--sk:#74B9FF;--pk:#FD79A8}body,input,button{font-family:'Outfit',system-ui,sans-serif}@keyframes fu{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}@keyframes fl{0%,100%{transform:translateY(0)}50%{transform:translateY(-12px)}}input:focus{outline:none}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-thumb{background:#DDD;border-radius:3px}`;

function Bd({theme}){const c=TC[theme];return c?<span style={{display:"inline-flex",alignItems:"center",gap:5,fontSize:12,fontWeight:600,color:c.color,background:c.bg,padding:"4px 12px",borderRadius:20}}>{c.icon} {c.label}</span>:null}
function IT({i}){return <span style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:12,fontWeight:600,color:"var(--ink)",background:"#F0E8DD",padding:"5px 14px",borderRadius:20}}>{i.icon} {i.label}</span>}
function Bar({v}){const c=v>70?"var(--li)":v>40?"var(--su)":"var(--ink3)";return <div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:50,height:5,background:"#F0E8DD",borderRadius:3,overflow:"hidden"}}><div style={{width:`${v}%`,height:"100%",background:c,borderRadius:3,transition:"width .5s ease"}}/></div><span style={{fontSize:11,color:"var(--ink3)",fontWeight:700}}>{v}%</span></div>}

function Card({f,i,onClick}){const[h,setH]=useState(false);const c=TC[f.theme];return <div onClick={onClick} onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)} style={{background:"var(--sf)",borderRadius:20,padding:"22px 24px",cursor:"pointer",border:`2px solid ${h?c?.color||"var(--el)":"var(--bd)"}`,boxShadow:h?"0 12px 40px rgba(108,92,231,.15)":"0 2px 8px rgba(108,92,231,.06)",transition:"all .25s ease",transform:h?"translateY(-4px)":"none",animation:`fu .4s ease ${i*.07}s both`,display:"flex",flexDirection:"column",gap:10,position:"relative",overflow:"hidden"}}><div style={{position:"absolute",top:0,left:0,right:0,height:4,background:c?.grad,borderRadius:"20px 20px 0 0",opacity:h?1:.5,transition:"opacity .2s"}}/><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",paddingTop:4}}><Bd theme={f.theme}/><Bar v={f.rel}/></div><h3 style={{fontSize:16,fontWeight:700,color:"var(--ink)",lineHeight:1.3}}>{f.titre}</h3><p style={{fontSize:13,color:"var(--ink2)",lineHeight:1.55,flex:1}}>{f.explicationSimple}</p><div style={{fontSize:11,color:"var(--ink3)",fontWeight:500}}>{f.question} · {f.sousTheme}</div></div>}

function Det({f,onClose}){if(!f)return null;const c=TC[f.theme];return <div style={{position:"fixed",inset:0,zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={onClose}><div style={{position:"absolute",inset:0,background:"rgba(26,26,46,.5)",backdropFilter:"blur(8px)"}}/><div onClick={e=>e.stopPropagation()} style={{position:"relative",background:"var(--sf)",borderRadius:24,maxWidth:640,width:"100%",maxHeight:"85vh",overflow:"auto",padding:32,boxShadow:"0 25px 60px rgba(108,92,231,.2)",animation:"fu .3s ease"}}><div style={{position:"absolute",top:0,left:0,right:0,height:5,background:c?.grad,borderRadius:"24px 24px 0 0"}}/><button onClick={onClose} style={{position:"absolute",top:16,right:16,background:"#F0E8DD",border:"none",borderRadius:"50%",width:34,height:34,cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center",color:"var(--ink2)",fontWeight:700}}>✕</button><div style={{paddingTop:8}}><Bd theme={f.theme}/></div><h2 style={{fontSize:22,fontWeight:800,color:"var(--ink)",margin:"14px 0 4px"}}>{f.titre}</h2><div style={{fontSize:12,color:"var(--ink3)",marginBottom:20}}>{f.questionLabel} · {f.sousTheme}</div><Sc t="📖 Définition" tx={f.definition} cl={c?.color}/><Sc t="💬 En simple" tx={f.explicationSimple} cl={c?.color}/><Sc t="⚙️ Mécanisme marketing" tx={f.mecanismeMarketing} cl={c?.color}/>{f.exemples?.length>0&&<div style={{marginBottom:18}}><div style={{fontSize:14,fontWeight:700,color:c?.color,marginBottom:8}}>📌 Exemples concrets</div>{f.exemples.map((e,i)=><div key={i} style={{background:"var(--bg)",borderRadius:14,padding:"14px 16px",marginBottom:8,borderLeft:`4px solid ${c?.color}`}}><div style={{fontWeight:700,fontSize:13,color:"var(--ink)",marginBottom:3}}>{e.marque}</div><div style={{fontSize:13,color:"var(--ink2)",lineHeight:1.5}}>{e.description}</div></div>)}</div>}{f.pistesDargumentation?.length>0&&<div style={{marginBottom:18}}><div style={{fontSize:14,fontWeight:700,color:c?.color,marginBottom:8}}>🎯 Pistes pour ton oral</div><div style={{display:"flex",flexDirection:"column",gap:7}}>{f.pistesDargumentation.map((p,i)=><div key={i} style={{display:"flex",gap:8,fontSize:13,color:"var(--ink)",lineHeight:1.5}}><span style={{color:c?.color,fontWeight:800,flexShrink:0}}>→</span>{p}</div>)}</div></div>}{f.liensAutresConcepts?.length>0&&<div><div style={{fontSize:14,fontWeight:700,color:c?.color,marginBottom:8}}>🔗 Concepts liés</div><div style={{display:"flex",flexWrap:"wrap",gap:6}}>{f.liensAutresConcepts.map(id=>{const lk=F.find(x=>x.id===id);return lk?<span key={id} style={{fontSize:12,color:"var(--el)",background:"#EDE9FF",padding:"4px 12px",borderRadius:20,fontWeight:600}}>{lk.titre}</span>:null})}</div></div>}</div></div>}
function Sc({t,tx,cl}){return <div style={{marginBottom:18}}><div style={{fontSize:14,fontWeight:700,color:cl,marginBottom:6}}>{t}</div><p style={{fontSize:14,color:"var(--ink2)",lineHeight:1.65}}>{tx}</p></div>}

/* ═══════════════════════════════════════════════════════════════
   🏠 APP
   ═══════════════════════════════════════════════════════════════ */
export default function App(){
  const[q,setQ]=useState("");const[res,setRes]=useState(null);const[sel,setSel]=useState(null);const[busy,setBusy]=useState(false);
  const[hist,setHist]=useState(()=>{try{return JSON.parse(window.localStorage?.getItem?.("go-h")||"[]")}catch{return[]}});
  const iR=useRef(null),rR=useRef(null);
  const go=useCallback(qr=>{const s=qr||q;if(!s.trim())return;setBusy(true);setTimeout(()=>{const r=search(s);setRes(r);setBusy(false);const nh=[s,...hist.filter(h=>h!==s)].slice(0,10);setHist(nh);try{window.localStorage?.setItem?.("go-h",JSON.stringify(nh))}catch{};setTimeout(()=>rR.current?.scrollIntoView({behavior:"smooth",block:"start"}),100)},250)},[q,hist]);
  const tap=qr=>{setQ(qr);go(qr)};

  return <div style={{minHeight:"100vh",background:"var(--bg)",position:"relative",overflow:"hidden"}}><style>{G}</style>

    {/* BLOBS */}
    <div style={{position:"fixed",top:-120,right:-120,width:400,height:400,borderRadius:"50%",background:"radial-gradient(circle,rgba(108,92,231,.12),transparent 70%)",pointerEvents:"none",animation:"fl 8s ease infinite"}}/>
    <div style={{position:"fixed",bottom:-100,left:-80,width:350,height:350,borderRadius:"50%",background:"radial-gradient(circle,rgba(253,121,168,.1),transparent 70%)",pointerEvents:"none",animation:"fl 10s ease infinite 2s"}}/>
    <div style={{position:"fixed",top:"40%",left:"60%",width:300,height:300,borderRadius:"50%",background:"radial-gradient(circle,rgba(253,203,110,.08),transparent 70%)",pointerEvents:"none",animation:"fl 12s ease infinite 4s"}}/>

    {/* HEADER */}
    <header style={{background:"rgba(255,251,245,.85)",backdropFilter:"blur(12px)",borderBottom:"1px solid var(--bd)",padding:"14px 24px",position:"sticky",top:0,zIndex:100}}>
      <div style={{maxWidth:920,margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:38,height:38,background:"linear-gradient(135deg,#6C5CE7,#FD79A8)",borderRadius:12,display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,color:"#fff",fontWeight:800}}>GO</div>
          <div><div style={{fontWeight:800,fontSize:17,color:"var(--ink)"}}>Grand Oral <span style={{color:"var(--el)"}}>Mercatique</span></div>
          <div style={{fontSize:11,color:"var(--ink3)"}}>Terminale STMG · {F.length} concepts</div></div>
        </div>
        <div style={{fontSize:11,color:"var(--ink3)",background:"var(--sf)",padding:"5px 14px",borderRadius:20,border:"1px solid var(--bd)",fontWeight:600}}>M. SEDDAR</div>
      </div>
    </header>

    <div style={{maxWidth:920,margin:"0 auto",padding:"48px 24px 32px",position:"relative",zIndex:1}}>
      {!res&&<div style={{textAlign:"center",marginBottom:40,animation:"fu .5s ease"}}>
        <div style={{display:"inline-block",background:"linear-gradient(135deg,#6C5CE7,#FD79A8,#FDCB6E)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",fontSize:11,fontWeight:800,textTransform:"uppercase",letterSpacing:".15em",marginBottom:12}}>Prépare ton épreuve</div>
        <h1 style={{fontSize:34,fontWeight:900,color:"var(--ink)",lineHeight:1.15,marginBottom:10}}>Entre ta question,<br/>découvre les <span style={{color:"var(--el)"}}>concepts clés</span></h1>
        <p style={{fontSize:16,color:"var(--ink2)",maxWidth:500,margin:"0 auto"}}>Analyse intelligente des notions, mécanismes et exemples du programme de Mercatique</p>
      </div>}

      <div style={{display:"flex",gap:10,marginBottom:res?10:28,animation:"fu .4s ease .1s both"}}>
        <div style={{flex:1}}><input ref={iR} type="text" value={q} onChange={e=>setQ(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="Entre ta question ici..." style={{width:"100%",padding:"15px 22px",fontSize:15,border:"2px solid var(--bd)",borderRadius:16,background:"var(--sf)",color:"var(--ink)",fontWeight:500,transition:"border-color .2s"}} onFocus={e=>e.target.style.borderColor="var(--el)"} onBlur={e=>e.target.style.borderColor="var(--bd)"}/></div>
        <button onClick={()=>go()} disabled={!q.trim()||busy} style={{padding:"15px 30px",background:q.trim()?"linear-gradient(135deg,#6C5CE7,#A29BFE)":"#DDD",color:"#fff",border:"none",borderRadius:16,fontWeight:700,fontSize:14,cursor:q.trim()?"pointer":"default",transition:"all .2s",whiteSpace:"nowrap",opacity:busy?.7:1}}>{busy?"...":"Analyser 🔍"}</button>
      </div>

      {!res&&<div style={{animation:"fu .4s ease .2s both"}}><div style={{fontSize:13,fontWeight:700,color:"var(--ink3)",marginBottom:10}}>💡 Essaie par exemple :</div><div style={{display:"flex",flexWrap:"wrap",gap:8}}>{EX.map((x,i)=><button key={i} onClick={()=>tap(x)} style={{padding:"9px 16px",fontSize:13,background:"var(--sf)",color:"var(--ink2)",border:"1.5px solid var(--bd)",borderRadius:24,cursor:"pointer",fontWeight:500,transition:"all .15s"}} onMouseEnter={e=>{e.target.style.borderColor="var(--el)";e.target.style.color="var(--el)";e.target.style.background="#EDE9FF"}} onMouseLeave={e=>{e.target.style.borderColor="var(--bd)";e.target.style.color="var(--ink2)";e.target.style.background="var(--sf)"}}>{x}</button>)}</div></div>}

      {!res&&hist.length>0&&<div style={{marginTop:24,animation:"fu .4s ease .3s both"}}><div style={{fontSize:12,fontWeight:700,color:"var(--ink3)",marginBottom:8}}>🕐 Historique</div><div style={{display:"flex",flexWrap:"wrap",gap:6}}>{hist.slice(0,5).map((x,i)=><button key={i} onClick={()=>tap(x)} style={{padding:"6px 14px",fontSize:12,background:"var(--bg)",color:"var(--ink3)",border:"1px solid var(--bd)",borderRadius:20,cursor:"pointer",fontWeight:500}}>{x.length>45?x.slice(0,45)+"…":x}</button>)}</div></div>}
    </div>

    {res&&<div ref={rR} style={{maxWidth:920,margin:"0 auto",padding:"0 24px 60px",position:"relative",zIndex:1}}>
      <div style={{background:"var(--sf)",borderRadius:20,padding:"22px 26px",border:"1px solid var(--bd)",marginBottom:24,animation:"fu .3s ease",boxShadow:"0 2px 8px rgba(108,92,231,.06)"}}>
        <div style={{fontSize:11,fontWeight:800,color:"var(--ink3)",textTransform:"uppercase",letterSpacing:".08em",marginBottom:8}}>Ta question</div>
        <div style={{fontSize:18,fontWeight:800,color:"var(--ink)",marginBottom:14}}>« {q} »</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:8,alignItems:"center"}}><span style={{fontSize:12,color:"var(--ink3)"}}>Intention :</span>{res.intents.map((x,i)=><IT key={i} i={x}/>)}<span style={{fontSize:12,color:"var(--ink3)",marginLeft:8}}>· {res.total} concept{res.total>1?"s":""}</span></div>
      </div>

      {res.principaux.length>0?<><div style={{fontSize:15,fontWeight:800,color:"var(--ink)",marginBottom:14,display:"flex",alignItems:"center",gap:8}}><span style={{width:26,height:26,background:"linear-gradient(135deg,#6C5CE7,#FD79A8)",color:"#fff",borderRadius:8,display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:800}}>★</span>Concepts principaux</div><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:14,marginBottom:28}}>{res.principaux.map((f,i)=><Card key={f.id} f={f} i={i} onClick={()=>setSel(f)}/>)}</div></>:<div style={{background:"var(--sf)",borderRadius:20,padding:"48px 24px",textAlign:"center",border:"1px solid var(--bd)",marginBottom:24}}><div style={{fontSize:36,marginBottom:12}}>🤔</div><div style={{fontSize:15,color:"var(--ink2)"}}>Aucun concept trouvé. Reformule avec des termes du programme Mercatique.</div></div>}

      {res.secondaires.length>0&&<><div style={{fontSize:14,fontWeight:700,color:"var(--ink3)",marginBottom:12}}>🔗 À explorer aussi</div><div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:28}}>{res.secondaires.map(f=><button key={f.id} onClick={()=>setSel(f)} style={{padding:"9px 18px",fontSize:13,background:"var(--sf)",color:"var(--ink2)",border:"1.5px solid var(--bd)",borderRadius:24,cursor:"pointer",fontWeight:600,transition:"all .15s"}} onMouseEnter={e=>{e.target.style.borderColor="var(--el)";e.target.style.color="var(--el)"}} onMouseLeave={e=>{e.target.style.borderColor="var(--bd)";e.target.style.color="var(--ink2)"}}>{f.titre}</button>)}</div></>}

      {res.pistes.length>0&&<div style={{background:"linear-gradient(135deg,#EDE9FF,#FFE8F0)",borderRadius:20,padding:"26px 30px",border:"1px solid #DDD5F3",animation:"fu .4s ease .3s both",marginBottom:28}}><div style={{fontSize:16,fontWeight:800,color:"var(--el)",marginBottom:14}}>🎯 Pistes pour ton Grand Oral</div><div style={{display:"flex",flexDirection:"column",gap:10}}>{res.pistes.map((p,i)=><div key={i} style={{display:"flex",gap:10}}><span style={{color:"var(--co)",fontWeight:800,fontSize:15,flexShrink:0}}>→</span><span style={{fontSize:14,color:"var(--ink)",lineHeight:1.55}}>{p}</span></div>)}</div></div>}

      <div style={{background:"var(--sf)",borderRadius:20,padding:"22px 26px",border:"1px solid var(--bd)",boxShadow:"0 2px 8px rgba(108,92,231,.06)"}}><div style={{fontSize:13,fontWeight:800,color:"var(--ink3)",marginBottom:12}}>📝 Critères d'évaluation du Grand Oral (/20)</div><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:8}}>{[{l:"Qualité orale",c:"var(--el)"},{l:"Prise de parole",c:"var(--co)"},{l:"Connaissances",c:"var(--li)"},{l:"Interaction",c:"var(--su)"},{l:"Argumentation",c:"var(--pk)"}].map((x,i)=><div key={i} style={{textAlign:"center",padding:"12px 8px",background:"var(--bg)",borderRadius:14,borderTop:`3px solid ${x.c}`}}><div style={{fontSize:12,fontWeight:700,color:"var(--ink)"}}>{x.l}</div><div style={{fontSize:11,color:"var(--ink3)",fontWeight:600}}>4 pts</div></div>)}</div></div>

      <div style={{textAlign:"center",marginTop:28}}><button onClick={()=>{setRes(null);setQ("");setTimeout(()=>iR.current?.focus(),100)}} style={{padding:"12px 28px",fontSize:14,background:"var(--sf)",color:"var(--el)",border:"2px solid var(--el)",borderRadius:14,cursor:"pointer",fontWeight:700,transition:"all .2s"}} onMouseEnter={e=>{e.target.style.background="var(--el)";e.target.style.color="#fff"}} onMouseLeave={e=>{e.target.style.background="var(--sf)";e.target.style.color="var(--el)"}}>← Nouvelle question</button></div>
    </div>}

    {sel&&<Det f={sel} onClose={()=>setSel(null)}/>}
    <footer style={{textAlign:"center",padding:"24px",fontSize:12,color:"var(--ink3)",borderTop:"1px solid var(--bd)",position:"relative",zIndex:1}}>Grand Oral Mercatique — Terminale STMG · {F.length} concepts · Programme officiel BO</footer>
  </div>
}
